    "code": "package main\n\nfunc alienOrder(words []string) string {\n\tadj := map[byte]map[byte]bool{}\n\tinDeg := map[byte]int{}\n\tfor _, w := range words {\n\t\tfor i := 0; i < len(w); i++ {\n\t\t\tif adj[w[i]] == nil {\n\t\t\t\tadj[w[i]] = map[byte]bool{}\n\t\t\t}\n\t\t\tinDeg[w[i]] += 0\n\t\t}\n\t}\n\tfor i := 0; i < len(words)-1; i++ {\n\t\tw1, w2 := words[i], words[i+1]\n\t\tif len(w1) > len(w2) && w1[:len(w2)] == w2 {\n\t\t\treturn \"\"\n\t\t}\n\t\tfor j := 0; j < len(w1) && j < len(w2); j++ {\n\t\t\tif w1[j] != w2[j] {\n\t\t\t\tif !adj[w1[j]][w2[j]] {\n\t\t\t\t\tadj[w1[j]][w2[j]] = true\n\t\t\t\t\tinDeg[w2[j]]++\n\t\t\t\t}\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\t}\n\tvar q []byte\n\tfor ch := range inDeg {\n\t\tif inDeg[ch] == 0 {\n\t\t\tq = append(q, ch)\n\t\t}\n\t}\n\tvar res []byte\n\tfor len(q) > 0 {\n\t\tch := q[0]\n\t\tq = q[1:]\n\t\tres = append(res, ch)\n\t\tfor nb := range adj[ch] {\n\t\t\tinDeg[nb]--\n\t\t\tif inDeg[nb] == 0 {\n\t\t\t\tq = append(q, nb)\n\t\t\t}\n\t\t}\n\t}\n\tif len(res) != len(inDeg) {\n\t\treturn \"\"\n\t}\n\treturn string(res)\n}\n",
