    "code": "package main\n\nconst INF = 1 << 30\n\nfunc floydWarshall(n int, edges [][]int, queries [][]int) []int {\n\tdist := make([][]int, n+1)\n\tfor i := range dist {\n\t\tdist[i] = make([]int, n+1)\n\t\tfor j := range dist[i] {\n\t\t\tdist[i][j] = INF\n\t\t}\n\t\tdist[i][i] = 0\n\t}\n\tfor _, e := range edges {\n\t\tu, v, w := e[0], e[1], e[2]\n\t\tdist[u][v] = w\n\t}\n\tfor k := 1; k <= n; k++ {\n\t\tfor i := 1; i <= n; i++ {\n\t\t\tfor j := 1; j <= n; j++ {\n\t\t\t\tif dist[i][k]+dist[k][j] < dist[i][j] {\n\t\t\t\t\tdist[i][j] = dist[i][k] + dist[k][j]\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\tresults := make([]int, len(queries))\n\tfor i, q := range queries {\n\t\tu, v := q[0], q[1]\n\t\tif u < 1 || u > n || v < 1 || v > n {\n\t\t\tresults[i] = -1\n\t\t} else {\n\t\t\tresults[i] = query(dist, u, v)\n\t\t}\n\t}\n\treturn results\n}\n\nfunc query(dist [][]int, u, v int) int {\n\tif dist[u][v] >= INF {\n\t\treturn -1\n\t}\n\treturn dist[u][v]\n}\n",
