    "code": "package main\n\nimport \"container/heap\"\n\ntype minHeap [][3]int\n\nfunc (h minHeap) Len() int            { return len(h) }\nfunc (h minHeap) Less(i, j int) bool  { return h[i][0] < h[j][0] }\nfunc (h minHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }\nfunc (h *minHeap) Push(x interface{}) { *h = append(*h, x.([3]int)) }\nfunc (h *minHeap) Pop() interface{} {\n\told := *h\n\tv := old[len(old)-1]\n\t*h = old[:len(old)-1]\n\treturn v\n}\n\nfunc swimInWater(grid [][]int) int {\n\tn := len(grid)\n\tvis := make([][]bool, n)\n\tfor i := range vis {\n\t\tvis[i] = make([]bool, n)\n\t}\n\th := &minHeap{{grid[0][0], 0, 0}}\n\tvis[0][0] = true\n\tdirs := [4][2]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}\n\tres := 0\n\tfor h.Len() > 0 {\n\t\tcur := heap.Pop(h).([3]int)\n\t\tif cur[0] > res {\n\t\t\tres = cur[0]\n\t\t}\n\t\tif cur[1] == n-1 && cur[2] == n-1 {\n\t\t\treturn res\n\t\t}\n\t\tfor _, d := range dirs {\n\t\t\tnr, nc := cur[1]+d[0], cur[2]+d[1]\n\t\t\tif nr >= 0 && nr < n && nc >= 0 && nc < n && !vis[nr][nc] {\n\t\t\t\tvis[nr][nc] = true\n\t\t\t\theap.Push(h, [3]int{grid[nr][nc], nr, nc})\n\t\t\t}\n\t\t}\n\t}\n\treturn res\n}\n",
