    "code": "package main\n\ntype WEdge struct {\n\tNext   int\n\tWeight int\n}\n\nfunc findShortestPathWithDijkstras(adj [][]WEdge, src int) []int {\n\tn := len(adj)\n\tdist := make([]int, n)\n\tused := make([]bool, n)\n\tfor i := range dist {\n\t\tdist[i] = int(^uint(0) >> 1)\n\t}\n\tdist[src] = 0\n\tfor count := 0; count < n; count++ {\n\t\tu := -1\n\t\tbest := int(^uint(0) >> 1)\n\t\tfor v := 0; v < n; v++ {\n\t\t\tif !used[v] && dist[v] < best {\n\t\t\t\tbest = dist[v]\n\t\t\t\tu = v\n\t\t\t}\n\t\t}\n\t\tif u == -1 {\n\t\t\tbreak\n\t\t}\n\t\tused[u] = true\n\t\tfor _, e := range adj[u] {\n\t\t\tif nd := dist[u] + e.Weight; nd < dist[e.Next] {\n\t\t\t\tdist[e.Next] = nd\n\t\t\t}\n\t\t}\n\t}\n\treturn dist\n}\n",
