    "time": "O(q·α(n))",
    "space": "O(n)",
    "code": "package main\n\nimport (\n\t\"fmt\"\n\t\"io\"\n)\n\ntype DSU struct {\n\tparent, size []int\n}\n\nfunc NewDSU(n int) *DSU {\n\tparent := make([]int, n+1)\n\tsize := make([]int, n+1)\n\tfor i := range parent {\n\t\tparent[i] = i\n\t\tsize[i] = 1\n\t}\n\treturn &DSU{parent, size}\n}\n\nfunc (d *DSU) Find(x int) int {\n\tif d.parent[x] != x {\n\t\td.parent[x] = d.Find(d.parent[x])\n\t}\n\treturn d.parent[x]\n}\n\nfunc (d *DSU) Union(x, y int) {\n\trx, ry := d.Find(x), d.Find(y)\n\tif rx == ry {\n\t\treturn\n\t}\n\tif d.size[rx] < d.size[ry] {\n\t\trx, ry = ry, rx\n\t}\n\td.parent[ry] = rx\n\td.size[rx] += d.size[ry]\n}\n\nfunc (d *DSU) Size(x int) int {\n\treturn d.size[d.Find(x)]\n}\n\nfunc SolveMergingCommunities(r io.Reader, w io.Writer) {\n\tvar n, q int\n\tif _, err := fmt.Fscan(r, &n, &q); err != nil {\n\t\treturn\n\t}\n\tdsu := NewDSU(n)\n\tfor i := 0; i < q; i++ {\n\t\tvar op string\n\t\tif _, err := fmt.Fscan(r, &op); err != nil {\n\t\t\treturn\n\t\t}\n\t\tif op == \"M\" {\n\t\t\tvar u, v int\n\t\t\tfmt.Fscan(r, &u, &v)\n\t\t\tdsu.Union(u, v)\n\t\t} else if op == \"Q\" {\n\t\t\tvar u int\n\t\t\tfmt.Fscan(r, &u)\n\t\t\tfmt.Fprintln(w, dsu.Size(u))\n\t\t}\n\t}\n}\n",
