    "code": "package main\n\nfunc numSimilarGroups(strs []string) int {\n\tn := len(strs)\n\tparent := make([]int, n)\n\tsize := make([]int, n)\n\tfor i := range parent {\n\t\tparent[i] = i\n\t\tsize[i] = 1\n\t}\n\tgroups := n\n\tfor i := 0; i < n; i++ {\n\t\tfor j := i + 1; j < n; j++ {\n\t\t\tdiffs := 0\n\t\t\tfor k := 0; k < len(strs[i]); k++ {\n\t\t\t\tif strs[i][k] != strs[j][k] {\n\t\t\t\t\tdiffs++\n\t\t\t\t\tif diffs > 2 {\n\t\t\t\t\t\tbreak\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\t\t\tif diffs == 0 || diffs == 2 {\n\t\t\t\tsimilarGroupsUnion(parent, size, &groups, i, j)\n\t\t\t}\n\t\t}\n\t}\n\treturn groups\n}\n\nfunc similarGroupsFind(parent []int, x int) int {\n\tif parent[x] != x {\n\t\tparent[x] = similarGroupsFind(parent, parent[x])\n\t}\n\treturn parent[x]\n}\n\nfunc similarGroupsUnion(parent, size []int, groups *int, x, y int) {\n\trx, ry := similarGroupsFind(parent, x), similarGroupsFind(parent, y)\n\tif rx == ry {\n\t\treturn\n\t}\n\tif size[rx] < size[ry] {\n\t\trx, ry = ry, rx\n\t}\n\tparent[ry] = rx\n\tsize[rx] += size[ry]\n\t*groups--\n}\n",
