    "time": "O(n·L·26)",
    "space": "O(n·L)",
    "code": "package main\n\nfunc ladderLength(beginWord string, endWord string, wordList []string) int {\n\twordSet := map[string]bool{}\n\tfor _, w := range wordList {\n\t\twordSet[w] = true\n\t}\n\tif !wordSet[endWord] {\n\t\treturn 0\n\t}\n\tq := []string{beginWord}\n\tsteps := 0\n\tfor len(q) > 0 {\n\t\tsteps++\n\t\tsz := len(q)\n\t\tfor i := 0; i < sz; i++ {\n\t\t\tcur := q[0]\n\t\t\tq = q[1:]\n\t\t\tif cur == endWord {\n\t\t\t\treturn steps\n\t\t\t}\n\t\t\tbuf := []byte(cur)\n\t\t\tfor j := 0; j < len(buf); j++ {\n\t\t\t\torig := buf[j]\n\t\t\t\tfor c := byte('a'); c <= 'z'; c++ {\n\t\t\t\t\tif c == orig {\n\t\t\t\t\t\tcontinue\n\t\t\t\t\t}\n\t\t\t\t\tbuf[j] = c\n\t\t\t\t\tw := string(buf)\n\t\t\t\t\tif wordSet[w] {\n\t\t\t\t\t\tq = append(q, w)\n\t\t\t\t\t\tdelete(wordSet, w)\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\tbuf[j] = orig\n\t\t\t}\n\t\t}\n\t}\n\treturn 0\n}\n",
