    "time": "O(m·n·k)",
    "space": "O(m·n·k)",
    "code": "package main\n\nfunc shortestPath(grid [][]int, k int) int {\n\tm, n := len(grid), len(grid[0])\n\tif m == 1 && n == 1 {\n\t\treturn 0\n\t}\n\tif k >= m+n-3 {\n\t\treturn m + n - 2\n\t}\n\tvis := make([][][]bool, m)\n\tfor i := range vis {\n\t\tvis[i] = make([][]bool, n)\n\t\tfor j := range vis[i] {\n\t\t\tvis[i][j] = make([]bool, k+1)\n\t\t}\n\t}\n\tq := [][3]int{{0, 0, k}}\n\tvis[0][0][k] = true\n\tdirs := [4][2]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}\n\tsteps := 0\n\tfor len(q) > 0 {\n\t\tsteps++\n\t\tsz := len(q)\n\t\tfor i := 0; i < sz; i++ {\n\t\t\tcur := q[0]\n\t\t\tq = q[1:]\n\t\t\tr, c, rem := cur[0], cur[1], cur[2]\n\t\t\tfor _, d := range dirs {\n\t\t\t\tnr, nc := r+d[0], c+d[1]\n\t\t\t\tif nr < 0 || nr >= m || nc < 0 || nc >= n {\n\t\t\t\t\tcontinue\n\t\t\t\t}\n\t\t\t\tnextRem := rem - grid[nr][nc]\n\t\t\t\tif nextRem < 0 || vis[nr][nc][nextRem] {\n\t\t\t\t\tcontinue\n\t\t\t\t}\n\t\t\t\tif nr == m-1 && nc == n-1 {\n\t\t\t\t\treturn steps\n\t\t\t\t}\n\t\t\t\tvis[nr][nc][nextRem] = true\n\t\t\t\tq = append(q, [3]int{nr, nc, nextRem})\n\t\t\t}\n\t\t}\n\t}\n\treturn -1\n}\n",
