    "code": "package main\n\nfunc maximumDetonation(bombs [][]int) int {\n\tn := len(bombs)\n\tadj := make([][]int, n)\n\tfor i := 0; i < n; i++ {\n\t\tfor j := 0; j < n; j++ {\n\t\t\tif i == j {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tdx := int64(bombs[i][0] - bombs[j][0])\n\t\t\tdy := int64(bombs[i][1] - bombs[j][1])\n\t\t\tr := int64(bombs[i][2])\n\t\t\tif dx*dx+dy*dy <= r*r {\n\t\t\t\tadj[i] = append(adj[i], j)\n\t\t\t}\n\t\t}\n\t}\n\tres := 0\n\tfor i := 0; i < n; i++ {\n\t\tvis := make([]bool, n)\n\t\tcnt := btDetonate(adj, vis, i)\n\t\tif cnt > res {\n\t\t\tres = cnt\n\t\t}\n\t}\n\treturn res\n}\n\nfunc btDetonate(adj [][]int, vis []bool, u int) int {\n\tvis[u] = true\n\tcnt := 1\n\tfor _, v := range adj[u] {\n\t\tif !vis[v] {\n\t\t\tcnt += btDetonate(adj, vis, v)\n\t\t}\n\t}\n\treturn cnt\n}\n",
