    "code": "package main\n\nfunc maximalNetworkRank(n int, roads [][]int) int {\n\tdeg := make([]int, n)\n\tedges := map[[2]int]bool{}\n\tfor _, r := range roads {\n\t\tu, v := r[0], r[1]\n\t\tdeg[u]++\n\t\tdeg[v]++\n\t\tif u > v {\n\t\t\tu, v = v, u\n\t\t}\n\t\tedges[[2]int{u, v}] = true\n\t}\n\tres := 0\n\tfor i := 0; i < n; i++ {\n\t\tfor j := i + 1; j < n; j++ {\n\t\t\trank := deg[i] + deg[j]\n\t\t\tif edges[[2]int{i, j}] {\n\t\t\t\trank--\n\t\t\t}\n\t\t\tif rank > res {\n\t\t\t\tres = rank\n\t\t\t}\n\t\t}\n\t}\n\treturn res\n}\n",
