    "leetcode": "https://leetcode.com/problems/number-of-good-paths/",
    "pattern": "Union-Find + sort by value",
    "visual": "Sort nodes by value; process in ascending order using Union-Find",
    "time": "O(n log n)",
    "space": "O(n)",
    "code": "package main\n\nimport \"sort\"\n\ntype idsByVal struct {\n\tvals []int\n\tids  []int\n}\n\nfunc (b idsByVal) Len() int { return len(b.ids) }\nfunc (b idsByVal) Less(i, j int) bool {\n\treturn b.vals[b.ids[i]] < b.vals[b.ids[j]]\n}\nfunc (b idsByVal) Swap(i, j int) { b.ids[i], b.ids[j] = b.ids[j], b.ids[i] }\n\nfunc numberOfGoodPaths(vals []int, edges [][]int) int {\n\tn := len(vals)\n\tparent := make([]int, n)\n\tfor i := range parent {\n\t\tparent[i] = i\n\t}\n\tadj := make([][]int, n)\n\tfor _, e := range edges {\n\t\tadj[e[0]] = append(adj[e[0]], e[1])\n\t\tadj[e[1]] = append(adj[e[1]], e[0])\n\t}\n\tids := make([]int, n)\n\tfor i := range ids {\n\t\tids[i] = i\n\t}\n\tsort.Sort(idsByVal{vals: vals, ids: ids})\n\tres := n\n\ti := 0\n\tfor i < n {\n\t\tj := i\n\t\tfor j < n && vals[ids[j]] == vals[ids[i]] {\n\t\t\tj++\n\t\t}\n\t\tfor k := i; k < j; k++ {\n\t\t\tu := ids[k]\n\t\t\tfor _, v := range adj[u] {\n\t\t\t\tif vals[v] <= vals[u] {\n\t\t\t\t\tgoodPathsUnion(parent, vals, u, v)\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t\tcnt := map[int]int{}\n\t\tfor k := i; k < j; k++ {\n\t\t\tcnt[goodPathsFind(parent, ids[k])]++\n\t\t}\n\t\tfor _, c := range cnt {\n\t\t\tres += c * (c - 1) / 2\n\t\t}\n\t\ti = j\n\t}\n\treturn res\n}\n\nfunc goodPathsFind(parent []int, x int) int {\n\tif parent[x] != x {\n\t\tparent[x] = goodPathsFind(parent, parent[x])\n\t}\n\treturn parent[x]\n}\n\nfunc goodPathsUnion(parent, vals []int, x, y int) {\n\trx, ry := goodPathsFind(parent, x), goodPathsFind(parent, y)\n\tif rx != ry {\n\t\tif vals[rx] < vals[ry] {\n\t\t\tparent[rx] = ry\n\t\t} else {\n\t\t\tparent[ry] = rx\n\t\t}\n\t}\n}\n",
