    "visual": "For each edge (u,v), extend with a neighbor of u and a neighbor of v (all distinct)",
    "time": "O(E)",
    "space": "O(V+E)",
    "code": "package main\n\nfunc maximumScore(scores []int, edges [][]int) int {\n\tn := len(scores)\n\ttop3 := make([][]int, n)\n\tfor _, e := range edges {\n\t\tu, v := e[0], e[1]\n\t\ttop3[u] = insertTop3(top3[u], v, scores)\n\t\ttop3[v] = insertTop3(top3[v], u, scores)\n\t}\n\tres := -1\n\tfor _, e := range edges {\n\t\tu, v := e[0], e[1]\n\t\tfor _, a := range top3[u] {\n\t\t\tif a == v {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tfor _, b := range top3[v] {\n\t\t\t\tif b == u || b == a {\n\t\t\t\t\tcontinue\n\t\t\t\t}\n\t\t\t\ts := scores[a] + scores[u] + scores[v] + scores[b]\n\t\t\t\tif s > res {\n\t\t\t\t\tres = s\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\treturn res\n}\n\nfunc insertTop3(top []int, node int, scores []int) []int {\n\ttop = append(top, node)\n\tfor i := len(top) - 1; i > 0; i-- {\n\t\tif scores[top[i]] > scores[top[i-1]] {\n\t\t\ttop[i], top[i-1] = top[i-1], top[i]\n\t\t}\n\t}\n\tif len(top) > 3 {\n\t\ttop = top[:3]\n\t}\n\treturn top\n}\n",
