    "code": "package main\n\nfunc coursesOrder(numCourses int, prerequisites [][]int) []int {\n\tadj := make([][]int, numCourses)\n\tindeg := make([]int, numCourses)\n\tfor _, p := range prerequisites {\n\t\tcourse, pre := p[0], p[1]\n\t\tadj[pre] = append(adj[pre], course)\n\t\tindeg[course]++\n\t}\n\tq := []int{}\n\tfor i, d := range indeg {\n\t\tif d == 0 {\n\t\t\tq = append(q, i)\n\t\t}\n\t}\n\tvar order []int\n\tfor len(q) > 0 {\n\t\tv := q[0]\n\t\tq = q[1:]\n\t\torder = append(order, v)\n\t\tfor _, nb := range adj[v] {\n\t\t\tindeg[nb]--\n\t\t\tif indeg[nb] == 0 {\n\t\t\t\tq = append(q, nb)\n\t\t\t}\n\t\t}\n\t}\n\tif len(order) != numCourses {\n\t\treturn nil\n\t}\n\treturn order\n}\n",
