    "code": "package main\n\nfunc numIslands(grid [][]byte) int {\n\tm, n := len(grid), len(grid[0])\n\tcnt := 0\n\tfor r := 0; r < m; r++ {\n\t\tfor c := 0; c < n; c++ {\n\t\t\tif grid[r][c] == '1' {\n\t\t\t\tcnt++\n\t\t\t\tbtFloodFill(grid, m, n, r, c)\n\t\t\t}\n\t\t}\n\t}\n\treturn cnt\n}\n\nfunc btFloodFill(grid [][]byte, m, n, r, c int) {\n\tif r < 0 || r >= m || c < 0 || c >= n || grid[r][c] != '1' {\n\t\treturn\n\t}\n\tgrid[r][c] = '0'\n\tbtFloodFill(grid, m, n, r+1, c)\n\tbtFloodFill(grid, m, n, r-1, c)\n\tbtFloodFill(grid, m, n, r, c+1)\n\tbtFloodFill(grid, m, n, r, c-1)\n}\n",
