    "code": "package main\n\nfunc criticalConnections(n int, connections [][]int) [][]int {\n\tadj := make([][]int, n)\n\tfor _, c := range connections {\n\t\tadj[c[0]] = append(adj[c[0]], c[1])\n\t\tadj[c[1]] = append(adj[c[1]], c[0])\n\t}\n\tdisc := make([]int, n)\n\tlow := make([]int, n)\n\tfor i := range disc {\n\t\tdisc[i] = -1\n\t}\n\ttimer := 0\n\tvar res [][]int\n\tbtTarjan(adj, 0, -1, disc, low, &timer, &res)\n\treturn res\n}\n\nfunc btTarjan(adj [][]int, u, parent int, disc, low []int, timer *int, res *[][]int) {\n\tdisc[u] = *timer\n\tlow[u] = *timer\n\t*timer++\n\tfor _, v := range adj[u] {\n\t\tif v == parent {\n\t\t\tcontinue\n\t\t}\n\t\tif disc[v] == -1 {\n\t\t\tbtTarjan(adj, v, u, disc, low, timer, res)\n\t\t\tif low[v] < low[u] {\n\t\t\t\tlow[u] = low[v]\n\t\t\t}\n\t\t\tif low[v] > disc[u] {\n\t\t\t\t*res = append(*res, []int{u, v})\n\t\t\t}\n\t\t} else if disc[v] < low[u] {\n\t\t\tlow[u] = disc[v]\n\t\t}\n\t}\n}\n",
