    "code": "package main\n\nfunc operatorCombinations(tokens []int) []int {\n\tmemo := make(map[string][]int)\n\treturn btOps(tokens, memo)\n}\n\nfunc btOps(t []int, memo map[string][]int) []int {\n\tkey := btIntsKey(t)\n\tif v, ok := memo[key]; ok {\n\t\treturn v\n\t}\n\tif len(t) == 1 {\n\t\treturn []int{t[0]}\n\t}\n\tres := make([]int, 0)\n\tfor i := 1; i < len(t); i++ {\n\t\tleft := btOps(t[:i], memo)\n\t\tright := btOps(t[i:], memo)\n\t\tfor _, a := range left {\n\t\t\tfor _, b := range right {\n\t\t\t\tres = append(res, a+b, a-b, a*b)\n\t\t\t\tif b != 0 {\n\t\t\t\t\tres = append(res, a/b)\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n\tmemo[key] = res\n\treturn res\n}\n\nfunc btIntsKey(a []int) string {\n\tkey := \"\"\n\tfor i, v := range a {\n\t\tif i > 0 {\n\t\t\tkey += \",\"\n\t\t}\n\t\tkey += btIntToString(v)\n\t}\n\treturn key\n}\n\nfunc btIntToString(n int) string {\n\tif n == 0 {\n\t\treturn \"0\"\n\t}\n\tneg := n < 0\n\tif neg {\n\t\tn = -n\n\t}\n\tdigits := make([]byte, 0)\n\tfor n > 0 {\n\t\tdigits = append([]byte{byte('0' + n%10)}, digits...)\n\t\tn /= 10\n\t}\n\tif neg {\n\t\treturn \"-\" + string(digits)\n\t}\n\treturn string(digits)\n}\n",
