    "code": "package main\n\ntype trieNode struct {\n\tchildren [26]*trieNode\n\tword     string\n}\n\nfunc findWords(board [][]byte, words []string) []string {\n\troot := &trieNode{}\n\tfor _, w := range words {\n\t\tcur := root\n\t\tfor i := 0; i < len(w); i++ {\n\t\t\tidx := w[i] - 'a'\n\t\t\tif cur.children[idx] == nil {\n\t\t\t\tcur.children[idx] = &trieNode{}\n\t\t\t}\n\t\t\tcur = cur.children[idx]\n\t\t}\n\t\tcur.word = w\n\t}\n\tm, n := len(board), len(board[0])\n\tvar res []string\n\tfor r := 0; r < m; r++ {\n\t\tfor c := 0; c < n; c++ {\n\t\t\tbtWordSearchII(board, m, n, r, c, root, &res)\n\t\t}\n\t}\n\treturn res\n}\n\nfunc btWordSearchII(board [][]byte, m, n, r, c int, node *trieNode, res *[]string) {\n\tif r < 0 || r >= m || c < 0 || c >= n || board[r][c] == '#' {\n\t\treturn\n\t}\n\tch := board[r][c]\n\tchild := node.children[ch-'a']\n\tif child == nil {\n\t\treturn\n\t}\n\tif child.word != \"\" {\n\t\t*res = append(*res, child.word)\n\t\tchild.word = \"\"\n\t}\n\tboard[r][c] = '#'\n\tbtWordSearchII(board, m, n, r+1, c, child, res)\n\tbtWordSearchII(board, m, n, r-1, c, child, res)\n\tbtWordSearchII(board, m, n, r, c+1, child, res)\n\tbtWordSearchII(board, m, n, r, c-1, child, res)\n\tboard[r][c] = ch\n}\n",
