        "text": "package main\n\nfunc minDistanceMemo(word1, word2 string) int {\n\tmemo := map[[2]int]int{}\n\treturn btEditDistance(word1, word2, 0, 0, memo)\n}\n\nfunc btEditDistance(word1, word2 string, i, j int, memo map[[2]int]int) int {\n\tif i == len(word1) {\n\t\treturn len(word2) - j\n\t}\n\tif j == len(word2) {\n\t\treturn len(word1) - i\n\t}\n\tkey := [2]int{i, j}\n\tif v, ok := memo[key]; ok {\n\t\treturn v\n\t}\n\tif word1[i] == word2[j] {\n\t\tmemo[key] = btEditDistance(word1, word2, i+1, j+1, memo)\n\t\treturn memo[key]\n\t}\n\tmemo[key] = 1 + min(\n\t\tbtEditDistance(word1, word2, i+1, j+1, memo),\n\t\tmin(btEditDistance(word1, word2, i+1, j, memo), btEditDistance(word1, word2, i, j+1, memo)),\n\t)\n\treturn memo[key]\n}\n"
